import { createClient } from "@/lib/supabase/server";
import Link from "next/link";
import { notFound } from "next/navigation";

interface PageProps {
  params: Promise<{ id: string }>;
}

export default async function PublicProfilePage({ params }: PageProps) {
  const { id } = await params;

  if (!id) {
    notFound();
  }

  const supabase = await createClient();

  const { data: profile, error } = await supabase
    .from("profiles")
    .select("first_name, last_name, bio, services, hourly_rate, avatar_url")
    .eq("id", id)
    .single();

  if (error || !profile) {
    return (
      <div className="min-h-screen bg-[#fef3ff] flex flex-col items-center justify-center text-[#3a264b] font-['Plus_Jakarta_Sans']">
        <div className="text-center">
          <span className="material-symbols-outlined text-6xl text-on-surface-variant mb-4 font-light">
            person_off
          </span>
          <h1 className="text-3xl font-extrabold mb-2">Profile Not Found</h1>
          <p className="text-on-surface-variant mb-6">
            We couldn't find the professional you're looking for.
          </p>
          <Link href="/" className="text-primary font-bold hover:underline">
            &larr; Back to Home
          </Link>
        </div>
      </div>
    );
  }

  const fullName =
    [profile.first_name, profile.last_name].filter(Boolean).join(" ") || "Professional";

  return (
    <div className="min-h-screen bg-[#fef3ff] text-[#3a264b] font-['Plus_Jakarta_Sans'] pb-12">
      <style
        dangerouslySetInnerHTML={{
          __html: `
        .glass-nav {
            background-color: rgba(255, 255, 255, 0.7);
            backdrop-filter: blur(12px);
        }
        .tonal-gradient {
            background: linear-gradient(135deg, #702ae1 0%, #b28cff 100%);
        }
      `,
        }}
      />
      {/* Top Navigation Bar */}
      <nav className="fixed top-0 w-full z-50 glass-nav shadow-sm">
        <div className="flex justify-between items-center px-6 py-4 max-w-7xl mx-auto">
          <div className="text-2xl font-extrabold text-purple-700 tracking-tighter">
            <Link href="/">
              <span style={{ color: "rgb(58, 38, 75)", letterSpacing: "-0.6px" }}>Guild</span>
            </Link>
          </div>
          <div className="hidden md:flex items-center gap-8">
            <Link
              href="/find-a-pro"
              className="text-purple-700 font-bold border-b-2 border-purple-600 pb-1 text-sm tracking-wide"
            >
              Find a Pro
            </Link>
            <Link
              href="/how-it-works"
              className="text-slate-500 hover:text-purple-500 transition-colors text-sm tracking-wide"
            >
              How it Works
            </Link>
          </div>
          <div className="flex items-center gap-4">
            <Link
              href="/auth/login"
              className="text-sm font-bold text-slate-600 hover:text-purple-700 transition-colors"
            >
              Log In
            </Link>
            <Link
              href="/be-a-pro"
              className="px-4 py-2 bg-purple-100 text-purple-700 rounded-full font-bold text-sm hover:bg-purple-200 transition-colors"
            >
              Be a Pro
            </Link>
          </div>
        </div>
      </nav>

      {/* Main Content Canvas */}
      <main className="pt-28 pb-12 px-6 max-w-4xl mx-auto">
        <div className="bg-white rounded-3xl shadow-sm border border-outline-variant/30 overflow-hidden">
          {/* Header */}
          <div className="p-8 md:p-12 border-b border-outline-variant/30 flex flex-col md:flex-row items-center md:items-start gap-8">
            <div className="w-32 h-32 md:w-40 md:h-40 shrink-0 rounded-full overflow-hidden bg-surface-container-high ring-4 ring-purple-50 flex items-center justify-center">
              {profile.avatar_url ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                  src={profile.avatar_url}
                  alt={fullName}
                  className="w-full h-full object-cover"
                />
              ) : (
                <span className="text-4xl font-extrabold text-primary">{fullName.charAt(0)}</span>
              )}
            </div>

            <div className="flex-1 text-center md:text-left flex flex-col items-center md:items-start">
              <h1 className="text-3xl md:text-4xl font-extrabold text-on-surface tracking-tight mb-2">
                {fullName}
              </h1>
              <div className="flex items-center gap-2 text-on-surface-variant font-medium mb-6">
                <span className="material-symbols-outlined text-xl">location_on</span>
                <span>Abuja, FCT</span>
              </div>
              <button className="px-8 py-3 w-full md:w-auto tonal-gradient text-white rounded-full font-bold text-sm shadow-md hover:shadow-lg transition-all active:scale-95">
                Send Proposal
              </button>
            </div>
          </div>

          {/* Body Content */}
          <div className="p-8 md:p-12 space-y-10">
            {/* Bio Section */}
            <section>
              <h2 className="text-xl font-bold text-on-surface mb-4">About</h2>
              <div className="prose prose-purple max-w-none text-on-surface-variant leading-relaxed">
                {profile.bio ? (
                  <p className="whitespace-pre-wrap">{profile.bio}</p>
                ) : (
                  <p className="italic opacity-70">This professional hasn't provided a bio yet.</p>
                )}
              </div>
            </section>

            {/* Services & Details Grid */}
            <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-surface-container-low p-6 rounded-2xl">
                <div className="flex items-center gap-3 mb-3">
                  <div className="w-10 h-10 rounded-full bg-secondary-container flex items-center justify-center text-on-secondary-container shrink-0">
                    <span className="material-symbols-outlined">handyman</span>
                  </div>
                  <h3 className="font-bold text-on-surface">Services & Specialty</h3>
                </div>
                <p className="text-sm text-on-surface-variant leading-relaxed ml-[52px]">
                  {profile.services || <span className="italic opacity-60">Not specified</span>}
                </p>
              </div>

              <div className="bg-surface-container-low p-6 rounded-2xl">
                <div className="flex items-center gap-3 mb-3">
                  <div className="w-10 h-10 rounded-full bg-tertiary-container flex items-center justify-center text-on-tertiary-container shrink-0">
                    <span className="material-symbols-outlined">payments</span>
                  </div>
                  <h3 className="font-bold text-on-surface">Hourly Rate</h3>
                </div>
                <div className="ml-[52px] text-2xl font-extrabold text-primary">
                  {profile.hourly_rate ? (
                    <>
                      ${profile.hourly_rate}
                      <span className="text-sm font-medium text-on-surface-variant">/hr</span>
                    </>
                  ) : (
                    <span className="text-sm font-medium italic opacity-60 text-on-surface-variant">
                      Custom pricing
                    </span>
                  )}
                </div>
              </div>
            </section>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="w-full py-12 px-6 border-t border-slate-100 bg-white">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="text-center md:text-left">
            <div className="text-lg font-bold text-purple-800 mb-2">Connect</div>
            <p className="text-xs font-medium text-slate-400">© 2024 Radiant Connect.</p>
          </div>
        </div>
      </footer>
    </div>
  );
}
